import{_ as e,o as t,c as i,a0 as n}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"Gintama: The Very Final — MyAnimeList Entry","description":"","frontmatter":{"type":"source","title":"Gintama: The Very Final — MyAnimeList Entry","tags":["gintama","anime","movie","final"],"related":["gintama","gintoki-sakata","yorozuya","utsuro","tendoshuu","altana","shinsengumi"],"sources":["anime/39486.md"],"created":"2026-07-10T00:00:00.000Z","updated":"2026-07-10T00:00:00.000Z","authors":[],"year":2021,"url":"https://myanimelist.net/anime/39486/Gintama__The_Final","venue":"MyAnimeList"},"headers":[],"relativePath":"docs/sources/5-anime--5-39486--1xtfkzd.md","filePath":"docs/sources/5-anime--5-39486--1xtfkzd.md","lastUpdated":1783686208000}'),r={name:"docs/sources/5-anime--5-39486--1xtfkzd.md"};function s(o,a,l,m,u,h){return t(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="gintama-the-very-final-—-myanimelist-entry" tabindex="-1">Gintama: The Very Final — MyAnimeList Entry <a class="header-anchor" href="#gintama-the-very-final-—-myanimelist-entry" aria-label="Permalink to &quot;Gintama: The Very Final — MyAnimeList Entry&quot;">​</a></h1><p>《Gintama: The Very Final》（银魂：最终篇）是《银魂》系列的最终章电影，于2021年上映，片长1集。在MyAnimeList上获得9.05的高评分，状态为&quot;Finished Airing&quot;。类型涵盖Action、Comedy、Drama、Sci-Fi。</p><h2 id="剧情概要" tabindex="-1">剧情概要 <a class="header-anchor" href="#剧情概要" aria-label="Permalink to &quot;剧情概要&quot;">​</a></h2><p>故事发生在<a href="/entities/天道众-tendoshuu">tendoshuu</a>入侵O-Edo Central Terminal两年之后。此时<a href="/entities/万事屋-yorozuya">yorozuya</a>成员已分道扬镳。<a href="/entities/坂田银时-gintoki-sakata">gintoki-sakata</a>预见到<a href="/entities/虚-utsuro">utsuro</a>的回归，开始勘测地球的龙脉（<a href="/concepts/阿尔塔纳-altana">altana</a>）以追踪虚的踪迹。在与仍在追寻永生的天道众残党遭遇后，银时返回江户。随后，重组后的<a href="/entities/真选组-shinsengumi">shinsengumi</a>与万事屋联手对被占领的Central Terminal发起进攻。</p><h2 id="元数据" tabindex="-1">元数据 <a class="header-anchor" href="#元数据" aria-label="Permalink to &quot;元数据&quot;">​</a></h2><ul><li><strong>MyAnimeList ID</strong>: 39486</li><li><strong>评分</strong>: 9.05</li><li><strong>集数</strong>: 1</li><li><strong>状态</strong>: Finished Airing</li><li><strong>年份</strong>: 2021</li><li><strong>类型</strong>: Action, Comedy, Drama, Sci-Fi</li></ul><h2 id="关联页面" tabindex="-1">关联页面 <a class="header-anchor" href="#关联页面" aria-label="Permalink to &quot;关联页面&quot;">​</a></h2><ul><li>作品实体：<a href="/entities/gintama-银魂">gintama</a></li><li>核心角色：<a href="/entities/坂田银时-gintoki-sakata">gintoki-sakata</a></li><li>核心组织：<a href="/entities/万事屋-yorozuya">yorozuya</a>、<a href="/entities/真选组-shinsengumi">shinsengumi</a>、<a href="/entities/天道众-tendoshuu">tendoshuu</a></li><li>核心反派：<a href="/entities/虚-utsuro">utsuro</a></li><li>核心概念：<a href="/concepts/阿尔塔纳-altana">altana</a></li></ul>',8)])])}const y=e(r,[["render",s]]);export{c as __pageData,y as default};
